import React, { useState } from 'react';

const AboutPage = () => {
  // Dark Mode State
  const [isDarkMode, setIsDarkMode] = useState(false);
  const toggleDarkMode = () => {
    setIsDarkMode(!isDarkMode);
    document.body.classList.toggle('dark-mode');
  };

  // Quiz States (Shortened for brevity, keep your existing quizData)
  const [currentIdx, setCurrentIdx] = useState(0);
  const [selectedIdx, setSelectedIdx] = useState(null);
  
  // Gallery arrays based on your HTML
  const row1 = ["ed6.png.jpg", "ed7.png.jpg", "ed8.png.jpg", "ed9.png.jpg", "ed10.png.jpg"];
  const row2 = ["ed18.png.jpg", "ed19.png.jpg", "ed20.png.jpg", "ed21.png.jpg", "ed22.png.jpg"];
  const row3 = ["ed11.png.jpg", "ed12.png.jpg", "ed2.png.jpg", "ed13.png.jpg", "ed14.png.jpg"];

  return (
    <main>
      <div style={{ textAlign: 'right', padding: '10px' }}>
        <button onClick={toggleDarkMode}>{isDarkMode ? '☀️' : '🌙'}</button>
      </div>

      <section className="hero">
        <h1>The Keeper of the Personal Gallery</h1>
      </section>

      {/* Gagamit tayo ng inline style para siguradong magkakatabi sila */}
      <section className="preview-grid-row">
        {row1.map((img, i) => (
          <div className="card-equal" key={i}>
            <img src={`/photos/${img}`} alt="gallery" />
          </div>
        ))}
      </section>

      <section className="preview-grid-row">
        {row2.map((img, i) => (
          <div className="card-equal" key={i}>
            <img src={`/photos/${img}`} alt="gallery" />
          </div>
        ))}
      </section>

      <section className="hero">
        <h1>The Curator of Collective Growth</h1>
      </section>

      <section className="preview-grid-row">
        {row3.map((img, i) => (
          <div className="card-equal" key={i}>
            <img src={`/photos/${img}`} alt="gallery" />
          </div>
        ))}
      </section>

      {/* Ipagpatuloy ang Quiz section mo dito... */}
    </main>
  );
};

export default AboutPage;
